use std::{env, fs, path::PathBuf};

use context_relay_protocol::*;
use ts_rs::TS;

fn declaration<T: TS>() -> String {
    format!("export {}\n", T::decl())
}

fn main() {
    let output = env::args_os()
        .nth(1)
        .map(PathBuf::from)
        .unwrap_or_else(|| PathBuf::from("apps/desktop/src/bindings.ts"));
    let mut bindings = format!(
        "// Generated by context-relay-protocol. Do not edit.\n\nexport const PROTOCOL_VERSION = {{ major: {PROTOCOL_MAJOR}, minor: {PROTOCOL_MINOR} }} as const;\n\n\
export type UuidV7 = string & {{ readonly __uuidV7: unique symbol }};\n\
export type Sha256Hex = string & {{ readonly __sha256Hex: unique symbol }};\n\
export type Base64Url = string & {{ readonly __base64Url: unique symbol }};\n\
export type PairingRequestNonceBase64Url = Base64Url & {{ readonly __pairingRequestNonce: unique symbol }};\n\
export type Ed25519PublicKeyBase64Url = Base64Url & {{ readonly __ed25519PublicKey: unique symbol }};\n\
export type X25519PublicKeyBase64Url = Base64Url & {{ readonly __x25519PublicKey: unique symbol }};\n\
export type InstallationTokenProofBase64Url = Base64Url & {{ readonly __installationTokenProof: unique symbol }};\n\
export type DecimalU64 = string & {{ readonly __decimalU64: unique symbol }};\nexport type PairingCodeString = string & {{ readonly __pairingCode: unique symbol }};\n\
export type AccountId = UuidV7 & {{ readonly __accountId: unique symbol }};\n\
export type WorkspaceId = UuidV7 & {{ readonly __workspaceId: unique symbol }};\n\
export type ProjectId = UuidV7 & {{ readonly __projectId: unique symbol }};\n\
export type MemoryId = UuidV7 & {{ readonly __memoryId: unique symbol }};\n\
export type CandidateId = UuidV7 & {{ readonly __candidateId: unique symbol }};\n\
export type TaskId = UuidV7 & {{ readonly __taskId: unique symbol }};\n\
export type SecretRefId = UuidV7 & {{ readonly __secretRefId: unique symbol }};\n\
export type OperationId = UuidV7 & {{ readonly __operationId: unique symbol }};\n\
export type RecordId = UuidV7 & {{ readonly __recordId: unique symbol }};\n\
export type PairingId = UuidV7 & {{ readonly __pairingId: unique symbol }};\n\
export type DeviceId = UuidV7 & {{ readonly __deviceId: unique symbol }};\n\
export type PlanId = UuidV7 & {{ readonly __planId: unique symbol }};\n\
export type PackageId = UuidV7 & {{ readonly __packageId: unique symbol }};\nexport type ExportId = UuidV7 & {{ readonly __exportId: unique symbol }};\n\n"
    );
    macro_rules! push { ($($ty:ty),+ $(,)?) => { $(bindings.push_str(&declaration::<$ty>());)+ }; }
    push!(
        ProtocolVersion,
        ProtocolVersionRange,
        ProtocolInfo,
        HybridLogicalClock,
        Sha256Digest,
        XChaChaNonce,
        Ed25519SignatureBytes,
        PairingRequestNonce,
        Ed25519PublicKeyBytes,
        X25519PublicKeyBytes,
        InstallationTokenProof,
        BoundedCiphertext,
        BoundedBytes,
        HarnessId,
        ScopeRef,
        MemoryKind,
        MemoryOrigin,
        CandidateState,
        TaskStatus,
        ComponentKind,
        ApprovalClass,
        ProvenanceSource,
        Provenance,
        MemoryRecord,
        MemoryCandidate,
        TaskEvidence,
        TaskRecord,
        SecretRef,
        InstructionRecord,
        ComponentRecord,
        HarnessAccessPolicy,
        ProjectIdentity,
        RecordKind,
        MutationKind,
        DeviceSequence,
        BlobRef,
        SyncOperationV1,
        CheckpointV1,
        ErrorCode,
        ClientError,
        NativePlatform,
        WireNativeValue,
        CapabilityLevel,
        InstallationMethod,
        ProbeContext,
        ProbeReport,
        NativeScope,
        ImportRequest,
        ImportedState,
        DesiredState,
        RenderedState,
        RenderedFile,
        ChangeClass,
        ClassifiedChange,
        SemanticDiff,
        CliOperation,
        ApplyReceipt,
        ValidationReport,
        ExpectedNativeDigest,
        PackageArtifact,
        PermissionDelta,
        NetworkScheme,
        NetworkEndpoint,
        NetworkDelta,
        SetupPlan,
        JsonRpcVersion,
        DaemonInstanceNonce,
        EmptyParams,
        ProjectParams,
        ProjectPathParams,
        MemoryParams,
        MemoryCreateParams,
        MemoryUpdateParams,
        MemoryArchiveParams,
        CandidateListParams,
        SearchParams,
        CandidateReviewParams,
        TaskParams,
        TaskCompleteParams,
        TaskTransitionParams,
        TaskUpsertParams,
        HandoffParams,
        HarnessParams,
        PlanParams,
        PackageParams,
        RetryParams,
        ExportParams,
        RecoveryParams,
        DeviceRevokeParams,
        DeviceRenameParams,
        CancelParams,
        HelloParams,
        PairingJoinParams,
        PairingIdParams,
        PairingDecisionParams,
        AccessSetParams,
        ExportChunkParams,
        AccountDeletionParams,
        RecoveryPhraseWords,
        PairingCode,
        PairingRequestInfo,
        DecimalTimestamp,
        ExportPayload,
        ClientRole,
        DeviceSummary,
        McpScopeSelector,
        DeviceState,
        RecoveryState,
        AccountDeletionState,
        LocalRequest,
        JsonRpcRequestV1,
        LocalResult,
        PairingState,
        JsonRpcSuccessV1,
        JsonRpcErrorObject,
        JsonRpcErrorV1,
        LocalProjectPath,
        SearchInput,
        SearchOutput,
        GetInput,
        ReadableRecord,
        GetOutput,
        RememberInput,
        RememberOutput,
        ProposeMemoryInput,
        ProposeMemoryOutput,
        UpdateMemoryInput,
        UpdateMemoryOutput,
        ArchiveMemoryInput,
        ArchiveMemoryOutput,
        ListTasksInput,
        ListTasksOutput,
        UpsertTaskInput,
        UpsertTaskOutput,
        CompletionEvidenceInput,
        CompleteTaskInput,
        CompleteTaskOutput,
        CreateHandoffInput,
        HandoffPayload,
        CreateHandoffOutput,
        StatusInput,
        VaultState,
        SyncState,
        StatusOutput,
        ImmutableDependency,
        PackageComponent,
        NamespacedExtension,
        PackageManifestV1,
        ExportedRecordV1,
        ExportEnvelopeV1
    );
    fs::write(output, bindings).expect("TypeScript bindings should be writable");
}
